  ('locality-814ced5a-moex-00276', 'locality-814ced5a', 'locality-814ced5a-moex-110-b3f42868', 'sub-locality-814ced5a-02', NULL, 'single_choice', '甲男與乙女已有婚姻關係，與丁女外遇生有一子戊男5歲，並定時給丁女、戊男生活費，試問戊男與甲男 的關係為下列何者？', '["擬制血親", "非婚生子女", "準正", "認領"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:29+00:00", "source_pdf_sha1": "21a81d36f6f5", "answer_pdf_sha1": "ec0c9969aea4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0110", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00277', 'locality-814ced5a', 'locality-814ced5a-moex-110-b3f42868', 'sub-locality-814ced5a-02', NULL, 'single_choice', '承上題，若甲男過世，不考慮其他情形下，關於產生的繼承問題，下列敘述何者正確？', '["乙女、丁女及戊男皆有繼承權", "僅乙女及戊男有繼承權", "僅乙女有繼承權", "僅丁女有繼承權"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:29+00:00", "source_pdf_sha1": "21a81d36f6f5", "answer_pdf_sha1": "ec0c9969aea4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0110", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00278', 'locality-814ced5a', 'locality-814ced5a-moex-110-b3f42868', 'sub-locality-814ced5a-02', NULL, 'single_choice', '為防止新冠肺炎（COVID-19）擴散造成社區感染，政府防疫措施要求大眾出入公共場所皆須配戴口罩；為 避免口罩價格飆漲，亦同時採行口罩凍漲政策。在其他條件不變下，上述政府措施，將對本國口罩市場造 成何種影響？', '["口罩價格較均衡價格低，需求數量大於供給數量", "口罩價格較均衡價格高，需求數量大於供給數量", "口罩價格較均衡價格低，供給數量大於需求數量", "口罩價格較均衡價格高，供給數量大於需求數量"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:29+00:00", "source_pdf_sha1": "21a81d36f6f5", "answer_pdf_sha1": "ec0c9969aea4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0110", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00279', 'locality-814ced5a', 'locality-814ced5a-moex-110-b3f42868', 'sub-locality-814ced5a-02', NULL, 'single_choice', '國際非政府組織「樂施會」在其2020年發表的報告中指出，全球貧富不均的狀況已經到達「失控」狀態， 而偏差的經濟體制放任極少數億萬富豪坐享鉅額財富卻對社會幾無貢獻，而新冠肺炎（COVID-19）病毒 的肆虐將又可能導致5億人陷於貧窮之中。關於上述對於貧富不均惡化現象所提到的偏差經濟體制，應是 指何種制度所帶來的負面影響？', '["共產主義強調效率至上的制度，導致資源誤置進而造成貧富差距惡化", "資本主義強調市場機能，於全球化趨勢加上技術進步下導致貧富差距惡化", "共產主義制度主張農工階級至上，但卻忽略資本家因而導致貧富不均", "資本主義追求分配公平，卻因此造成生產力下降，反而拉大貧富差距"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:29+00:00", "source_pdf_sha1": "21a81d36f6f5", "answer_pdf_sha1": "ec0c9969aea4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0110", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00280', 'locality-814ced5a', 'locality-814ced5a-moex-110-b3f42868', 'sub-locality-814ced5a-02', NULL, 'single_choice', 'X與Y兩財貨具有聯合供給的關係，若X價格上漲，對Y財貨的影響為何？', '["供給曲線右移，供給量增加", "供給曲線右移，供給量減少", "供給曲線左移，供給量增加", "供給曲線左移，供給量減少"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:29+00:00", "source_pdf_sha1": "21a81d36f6f5", "answer_pdf_sha1": "ec0c9969aea4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0110", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
